async function main() {
  console.log(`\n=== PR Freelance Scrape Import — 2026-05-07 ===\n`);
  console.log(`${LEADS.length} leads queued. Pipeline: pr-freelance.\n`);

  let created = 0;
  let skipped = 0;
  let errors = 0;

  for (const lead of LEADS) {
    try {
      const existing = await prisma.company.findFirst({
        where: { name: lead.company.name },
      });

      if (existing) {
        console.log(`SKIP  ${lead.company.name} (already in DB, id=${existing.id})`);
        skipped += 1;
        continue;
      }

      const enhanced = ENHANCED[lead.company.name] || {};

      // Merge enhanced fields into notes payload (compatible with existing schema —
      // the dedicated columns can be added in a follow-up migration if not yet present).
      const enhancedNote = `\n\n--- ICP-Enhanced Fields (2026-05-06 schema upgrade) ---\nvertical: ${enhanced.vertical}\nsubvertical: ${enhanced.subvertical}\nengagementModel: ${enhanced.engagementModel}\nbuyerType: ${enhanced.buyerType}\ncompensationText: ${enhanced.compensationText}\nremoteFlag: ${enhanced.remoteFlag}\nemploymentTypeRaw: ${enhanced.employmentTypeRaw}\nurgencyScore: ${enhanced.urgencyScore}`;

      const company = await prisma.company.create({
        data: {
          name: lead.company.name,
          website: lead.company.website,
          pipeline: lead.company.pipeline,
          industry: lead.company.industry,
          size: lead.company.size,
          location: lead.company.location,
          fundingStage: lead.company.fundingStage,
          techStack: lead.company.techStack,
          fitScore: lead.company.fitScore,
          intentScore: lead.company.intentScore,
          fitDetails: lead.company.fitDetails,
          intentDetails: lead.company.intentDetails,
          starred: lead.company.starred,
          notes: lead.company.notes + enhancedNote,
          source: lead.company.source,
          lastActivity: lead.company.lastActivity,
        },
      });

      for (const c of lead.contacts) {
        await prisma.contact.create({
          data: {
            companyId: company.id,
            name: c.name,
            title: c.title,
            persona: c.persona,
            decisionMaker: c.decisionMaker,
          },
        });
      }

      await prisma.scrapeResult.create({
        data: {
          companyId: company.id,
          source: lead.scrape.source,
          url: lead.scrape.url,
          matchedSignals: lead.scrape.matchedSignals,
          fitScore: lead.company.fitScore,
          intentScore: lead.company.intentScore,
        },
      });

      console.log(`OK    ${lead.company.name} (id=${company.id})`);
      created += 1;
    } catch (err) {
      console.error(`ERROR ${lead.company.name}: ${err.message}`);
      errors += 1;
    }
  }

  console.log(`\n=== Summary ===`);
  console.log(`Created: ${created}`);
  console.log(`Skipped (duplicate): ${skipped}`);
  console.log(`Errors: ${errors}\n`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
